      if (!mgCodeDescs[mg.mg_code]) mgCodeDescs[mg.mg_code] = [];
      if (mg.mg_desc && !mgCodeDescs[mg.mg_code].includes(mg.mg_desc)) {
        mgCodeDescs[mg.mg_code].push(mg.mg_desc);
      }
    }

    // mg_code (licensor group 05) → LicensingTime record
    const licTimeCache = globalThis.sql.LicensingTimeCache;
    const mgLicTimesMap = {};
    for (const [code, descs] of Object.entries(mgCodeDescs)) {
      for (const desc of descs) {
        const match = fuzzyMatchLicensor(desc, licTimeCache);
        if (match) { mgLicTimesMap[code] = match; break; }
      }
    }
    globalThis.sql.MgLicTimesMap = mgLicTimesMap;
    console.log(`Built LicensingTime map for ${Object.keys(mgLicTimesMap).length} mg_codes.`);

    // mg_code (product type group 01) → FactoryTime record
    // Used to calculate factory days for needed-date backwards calculation.
    const allFactory = await db.FactoryTime.findAll();
    const factoryCache = allFactory.map(r => r.dataValues);
    const mgFactoryTimesMap = {};
    for (const [code, descs] of Object.entries(mgCodeDescs)) {
      for (const desc of descs) {
        const match = fuzzyMatch(desc, factoryCache, 'product_subtype');
        if (match) { mgFactoryTimesMap[code] = match; break; }
      }
    }
    globalThis.sql.MgFactoryTimesMap = mgFactoryTimesMap;
    console.log(`Built FactoryTime map for ${Object.keys(mgFactoryTimesMap).length} mg_codes.`);

    app.listen(port, function () {
