const express = require("express");
const httpProxy = require("http-proxy");
const { SERVICE_MAP } = require("../src/serviceMap");
const { attachInvokingIdentityHeaders } = require("../src/backendProxy");

const router = express.Router();

const proxy = httpProxy.createProxyServer({
  xfwd: true,
  proxyTimeout: 0,
  timeout: 0,
});

proxy.on("error", (err, req, res) => {
  console.error("[BFF proxy error]", err?.message || err);
  if (res && !res.headersSent && typeof res.writeHead === "function") {
    res.writeHead(502, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: "Bad gateway" }));
  }
});

/**
 * /api/<service>/<backend-path>
 * Example: /api/core/getAllItems, /api/item_master/lib/getAllitems
 */
router.use(async (req, res) => {
  const pathname = req.path.replace(/^\//, "");
  const segments = pathname.split("/").filter(Boolean);
  const service = segments[0];
  const backendPath = segments.slice(1).join("/");

  const backendUrl = SERVICE_MAP[service];
  if (!backendUrl) {
    return res.status(404).json({
      error: `Unknown backend service: ${service}`,
    });
  }
  if (!backendPath) {
    return res.status(404).json({ error: "Missing backend path" });
  }

  const qIdx = req.url.indexOf("?");
  const search = qIdx !== -1 ? req.url.substring(qIdx) : "";

  try {
    await attachInvokingIdentityHeaders(backendUrl, req);
    req.url = `/${backendPath}${search}`;

    proxy.web(req, res, {
      target: backendUrl.replace(/\/$/, ""),
      changeOrigin: true,
    });
  } catch (err) {
    console.error(`[BFF ERROR] ${service} ${req.method} ${req.originalUrl}`, err.message);
    if (!res.headersSent) {
      res
        .status(err.response?.status || 500)
        .send(err.response?.data || { error: err.message || "Backend request failed" });
    }
  }
});

module.exports = router;

