import { getServiceBaseUrls } from "../config/settings.js";

export type DesignflowService = "core" | "itemMaster" | "tracking" | "dataSync";

type RequestOptions = {
  method?: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
  query?: Record<string, string | number | boolean | undefined>;
  body?: unknown;
  headers?: Record<string, string>;
};

export class DesignflowClient {
  private readonly bases = getServiceBaseUrls();
  private readonly userJwt = process.env.DESIGNFLOW_USER_JWT;
  private readonly syncApiKey = process.env.DFLOW_SYNC_API_KEY;

  async request<T = unknown>(service: DesignflowService, route: string, options: RequestOptions = {}): Promise<T> {
    const base = this.bases[service].replace(/\/$/, "");
    const url = new URL(`${base}/${route.replace(/^\//, "")}`);

    for (const [key, value] of Object.entries(options.query ?? {})) {
      if (value !== undefined) {
        url.searchParams.set(key, String(value));
      }
    }

    const headers: Record<string, string> = {
      Accept: "application/json",
      ...(options.headers ?? {}),
    };

    if (this.userJwt) {
      headers.Authorization = this.userJwt.startsWith("Bearer ") ? this.userJwt : `Bearer ${this.userJwt}`;
    }

    if (service === "dataSync" && this.syncApiKey) {
      headers["X-API-Key"] = this.syncApiKey;
    }

    if (options.body !== undefined) {
      headers["Content-Type"] = "application/json";
    }

    const response = await fetch(url, {
      method: options.method ?? (options.body === undefined ? "GET" : "POST"),
      headers,
      body: options.body === undefined ? undefined : JSON.stringify(options.body),
    });

    const text = await response.text();
    const data = text ? safeJson(text) : null;

    if (!response.ok) {
      throw new Error(
        `Designflow ${service} ${response.status} ${response.statusText}: ${
          typeof data === "string" ? data : JSON.stringify(data)
        }`
      );
    }

    return data as T;
  }
}

const safeJson = (text: string): unknown => {
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

import fs from "node:fs";
import path from "node:path";

type ToolsConfig = {
  enabled_read_tools?: string[];
  enabled_write_tools?: string[];
};

const splitCsv = (value: string | undefined): string[] =>
  (value ?? "")
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);

export const loadToolConfig = (cwd: string): Set<string> => {
  const configPath = path.join(cwd, "tools-config.json");
  const raw = fs.existsSync(configPath) ? fs.readFileSync(configPath, "utf8") : "{}";
  const parsed = JSON.parse(raw) as ToolsConfig;

  const enabled = new Set<string>([
    ...(parsed.enabled_read_tools ?? []),
    ...(parsed.enabled_write_tools ?? []),
    ...splitCsv(process.env.DESIGNFLOW_MCP_ENABLED_TOOLS),
  ]);

  for (const disabled of splitCsv(process.env.DESIGNFLOW_MCP_DISABLED_TOOLS)) {
    enabled.delete(disabled);
  }

  return enabled;
};

export const getServiceBaseUrls = () => ({
  core: process.env.DESIGNFLOW_CORE_BASE_URL ?? "http://localhost:5004/api/core",
  itemMaster: process.env.DESIGNFLOW_ITEM_MASTER_BASE_URL ?? "http://localhost:5004/api/item_master",
  tracking: process.env.DESIGNFLOW_TRACKING_BASE_URL ?? "http://localhost:5004/api/tracking",
  dataSync: process.env.DESIGNFLOW_DATA_SYNC_BASE_URL ?? "http://localhost:5004/api/data_sync",
});

