import express, { type Request, type Response } from "express";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
import { createDesignflowMcpServer } from "./server.js";

const runStdio = async () => {
  const server = createDesignflowMcpServer();
  const transport = new StdioServerTransport();
  await server.connect(transport);
};

const runHttp = async () => {
  const app = express();
  app.use(express.json({ limit: "2mb" }));

  app.get("/health", (_req, res) => {
    res.json({ status: "ok", service: "designflow-mcp" });
  });

  app.post("/mcp", async (req: Request, res: Response) => {
    const server = createDesignflowMcpServer();
    const transport = new StreamableHTTPServerTransport({
      sessionIdGenerator: undefined,
    });

    try {
      await server.connect(transport);
      await transport.handleRequest(req, res, req.body);
      res.on("close", () => {
        void transport.close();
        void server.close();
      });
    } catch (error) {
      console.error("Error handling MCP request:", error);
      if (!res.headersSent) {
        res.status(500).json({
          jsonrpc: "2.0",
          error: { code: -32603, message: "Internal server error" },
          id: null,
        });
      }
    }
  });

  app.get("/mcp", (_req, res) => {
    res.status(405).json({
      jsonrpc: "2.0",
      error: { code: -32000, message: "Method not allowed. This stateless server accepts POST /mcp." },
      id: null,
    });
  });

  app.delete("/mcp", (_req, res) => {
    res.status(405).json({
      jsonrpc: "2.0",
      error: { code: -32000, message: "Method not allowed. This stateless server does not maintain sessions." },
      id: null,
    });
  });

  const port = Number(process.env.MCP_PORT ?? 3010);
  app.listen(port, () => {
    console.log(`Designflow MCP Streamable HTTP server listening on port ${port}`);
  });
};

const mode = process.argv.includes("--stdio") ? "stdio" : "http";

if (mode === "stdio") {
  await runStdio();
} else {
  await runHttp();
}

