export const formatToolContract = (tool: ToolDef): string => {
  const related = tool.relatedTools?.length ? tool.relatedTools.join(", ") : "none";
  return [
    `# ${tool.name}`,
    "",
    `Title: ${tool.title}`,
    `Group: ${tool.group}`,
    `Safety: tier ${tool.safety.tier} (${tool.safety.label}) - ${tool.safety.description}`,
    "",
    "Description:",
