import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StdioClientTransport } from "@modelcontextprotocol/sdk/client/stdio.js";
import { describe, expect, it } from "vitest";

describe("Designflow MCP server", () => {
  it("keeps the visible tools/list surface intentionally small", async () => {
    const client = new Client({ name: "designflow-mcp-test", version: "0.1.0" });
    const transport = new StdioClientTransport({
      command: "node",
      args: ["dist/index.js", "--stdio"],
    });

    await client.connect(transport);
    try {
      const tools = await client.listTools();

      expect(tools.tools.map((tool) => tool.name).sort()).toEqual(
        ["get_capability_details", "health", "invoke_tool", "list_capabilities", "tool_search"].sort()
      );
    } finally {
      await client.close();
    }
  });
});

import { describe, expect, it } from "vitest";
import { ToolCatalog, formatToolContract } from "../../src/registry/catalog.js";

describe("ToolCatalog", () => {
  it("searches enabled hidden tools by keyword without requiring eager registration", () => {
    const catalog = new ToolCatalog(new Set(["get_item_images", "get_sample_photos"]));

    const results = catalog.search("item images");

    expect(results.map((tool) => tool.name)).toContain("get_item_images");
  });

  it("does not return tools that are compiled but not enabled", () => {
    const catalog = new ToolCatalog(new Set(["get_item_images"]));

    const results = catalog.search("sample photos");

    expect(results.map((tool) => tool.name)).not.toContain("get_sample_photos");
    expect(catalog.get("get_sample_photos")).toBeUndefined();
  });

  it("formats contracts with exact invoke_tool shape", () => {
    const catalog = new ToolCatalog(new Set(["get_item_images"]));
    const tool = catalog.get("get_item_images");

    expect(tool).toBeDefined();
    expect(formatToolContract(tool!)).toContain('"name": "get_item_images"');
    expect(formatToolContract(tool!)).toContain('"itemId": 12345');
  });

  it("filters capabilities by group and safety tier", () => {
    const catalog = new ToolCatalog(new Set(["get_item_images", "get_api_inventory"]));

    const summaries = catalog.listCapabilities({ group: "images", safety: 1 });

    expect(summaries).toHaveLength(1);
    expect(summaries[0].name).toBe("get_item_images");
  });
});

import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, describe, expect, it } from "vitest";
import { loadToolConfig } from "../../src/config/settings.js";

const oldEnabled = process.env.DESIGNFLOW_MCP_ENABLED_TOOLS;
const oldDisabled = process.env.DESIGNFLOW_MCP_DISABLED_TOOLS;

afterEach(() => {
  process.env.DESIGNFLOW_MCP_ENABLED_TOOLS = oldEnabled;
  process.env.DESIGNFLOW_MCP_DISABLED_TOOLS = oldDisabled;
});

const makeTempConfig = (config: unknown): string => {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), "designflow-mcp-"));
  fs.writeFileSync(path.join(dir, "tools-config.json"), JSON.stringify(config));
  return dir;
};

describe("loadToolConfig", () => {
  it("loads read and write tool names from tools-config.json", () => {
    const cwd = makeTempConfig({
      enabled_read_tools: ["get_item_images"],
      enabled_write_tools: ["future_write_tool"],
    });

    const enabled = loadToolConfig(cwd);

    expect(enabled.has("get_item_images")).toBe(true);
    expect(enabled.has("future_write_tool")).toBe(true);
  });

  it("applies environment enabled and disabled overrides with disabled winning", () => {
    const cwd = makeTempConfig({
      enabled_read_tools: ["get_item_images"],
      enabled_write_tools: [],
    });
    process.env.DESIGNFLOW_MCP_ENABLED_TOOLS = "get_sample_photos";
    process.env.DESIGNFLOW_MCP_DISABLED_TOOLS = "get_item_images";

    const enabled = loadToolConfig(cwd);

    expect(enabled.has("get_sample_photos")).toBe(true);
    expect(enabled.has("get_item_images")).toBe(false);
  });
});
